public static void removeEvens(List<Integer> list) {
 Iterator<Integer> it = list.iterator();
 while(it.hasNext()) {
 Integer num = it.next();
 if(num % 2 == 0) {
 it.remove(); // Safe removal
 }
 }
}

public static void demonstrateListIterator(List<String> list) {
 ListIterator<String> it = list.listIterator();

 // Forward traversal
 System.out.println("Forward: ");
 while(it.hasNext()) {
 System.out.println(it.nextIndex() + ": " + it.next());
 }

 // Backward traversal
 System.out.println("Backward: ");
 while(it.hasPrevious()) {
 System.out.println(it.previousIndex() + ": " + it.previous());
 }

 // Add element
 it = list.listIterator();
 it.next();
 it.add("X"); // Inserts before current position
 System.out.println("After add: " + list);
}

public static void iterateModern(Collection<Integer> col) {
 Iterator<Integer> it = col.iterator();

 // Traditional approach
 while(it.hasNext()) {
 System.out.println(it.next());
 }

 // Java 8+ forEachRemaining
 it = col.iterator();
 it.forEachRemaining(System.out::println);

 // Using forEach directly (uses iterator internally)
 col.forEach(System.out::println);
}
